import React, { useContext } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

// 1. Import Context (Lưu ý dùng dấu { } vì là Named Export)
import { AuthProvider, AuthContext } from './context/AuthContext';
import { DataProvider } from './context/DataContext';

// 2. Import Pages
import LoginForm from './components/LoginForm';

// Admin Pages
import TaskManager from './pages/Admin/TaskManager';
import DisciplineManager from './pages/Admin/DisciplineManager';
import StaffManager from './pages/Admin/StaffManager';
import Reports from './pages/Admin/Reports';

// Staff Pages
import MyTasks from './pages/Staff/MyTasks';
import FacilityCheck from './pages/Staff/FacilityCheck';
import Performance from './pages/Staff/Performance';
// import Attendance from './pages/Staff/Attendance'; // Nếu có

// 3. Component bảo vệ Route (Kiểm tra đăng nhập)
const PrivateRoute = ({ children, allowedRoles }) => {
  const { user } = useContext(AuthContext);

  if (!user) {
    return <Navigate to="/" />;
  }

  // Nếu có quy định role cụ thể (logic đơn giản)
  if (allowedRoles && !allowedRoles.includes(user.role)) {
     // Cho phép Staff vào trang Staff, Admin vào trang Admin
     if (user.role === 'Staff' && !allowedRoles.includes('Staff')) return <Navigate to="/staff/tasks" />;
     if (user.role !== 'Staff' && allowedRoles.includes('Staff')) return <Navigate to="/admin/tasks" />;
  }

  return children;
};

// 4. App Component chính
function App() {
  return (
    <AuthProvider>
      <DataProvider>
        <Router>
          <Routes>
            {/* Login Route */}
            <Route path="/" element={<LoginForm />} />

            {/* Admin Routes */}
            <Route path="/admin/tasks" element={<PrivateRoute><TaskManager /></PrivateRoute>} />
            <Route path="/admin/discipline" element={<PrivateRoute><DisciplineManager /></PrivateRoute>} />
            <Route path="/admin/staff" element={<PrivateRoute><StaffManager /></PrivateRoute>} />
            <Route path="/admin/reports" element={<PrivateRoute><Reports /></PrivateRoute>} />

            {/* Staff Routes */}
            <Route path="/staff/tasks" element={<PrivateRoute><MyTasks /></PrivateRoute>} />
            <Route path="/staff/facility" element={<PrivateRoute><FacilityCheck /></PrivateRoute>} />
            <Route path="/staff/performance" element={<PrivateRoute><Performance /></PrivateRoute>} />

            {/* Redirect mặc định */}
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </Router>
      </DataProvider>
    </AuthProvider>
  );
}

export default App;
